import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import { CallToolRequestSchema, ListToolsRequestSchema } from '@modelcontextprotocol/sdk/types.js';

const server = new Server(
  { name: 'clipboard-translate', version: '0.1.0' },
  { capabilities: { tools: {} } },
);

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [{
    name: 'translate',
    description: 'Translate clipboard text into formal English email tone.',
    inputSchema: {
      type: 'object',
      properties: { text: { type: 'string' } },
      required: ['text'],
    },
  }],
}));

server.setRequestHandler(CallToolRequestSchema, async (req) => {
  const { text } = req.params.arguments as { text: string };
  // The kernel injects an llm capability via the host bridge.
  const translated = await globalThis.ctrl.llm.call('clipboard-translate-formal-en', { input: text });
  return { content: [{ type: 'text', text: translated }] };
});

const transport = new StdioServerTransport();
await server.connect(transport);
